SELECT AVG(order_count) AS average_orders_per_customer
FROM (
    SELECT customer_id, COUNT(order_id) AS order_count
    FROM orders
    GROUP BY customer_id
);

SELECT COUNT(DISTINCT customer_id) 
FROM customer_interactions 
WHERE campaign_id = 456;

SELECT user_id, role, permissions
FROM security_access
WHERE LENGTH(permissions) = (
    SELECT MAX(LENGTH(permissions))
    FROM security_access
);

SELECT COUNT(user_id) AS total_users
FROM security_access
WHERE permissions LIKE '%place orders%';

SELECT c.first_name, o.order_date
FROM customers c
JOIN orders o ON c.customer_id = o.customer_id;

SELECT role, COUNT(user_id) AS total_users
FROM security_access
GROUP BY role;
